  8→import androidx.recyclerview.widget.DiffUtil
  9→import androidx.recyclerview.widget.RecyclerView.ViewHolder
 10→import org.wordpress.android.R
 11→import org.wordpress.android.fluxc.model.LocalOrRemoteId.LocalId
 12→import org.wordpress.android.fluxc.model.LocalOrRemoteId.RemoteId
 13→import org.wordpress.android.ui.posts.PostListItemViewHolder
 14→import org.wordpress.android.ui.utils.UiHelpers
 15→import org.wordpress.android.util.image.ImageManager
 16→import org.wordpress.android.viewmodel.posts.PostListItemType
