252→    private fun editPost(site: SiteModel, post: PostModel) {
253→        if (UploadService.isPostUploadingOrQueued(post)) {
254→            // If the post is uploading media, allow the media to continue uploading, but don't upload the
255→            // post itself when they finish (since we're about to edit it again)
256→            UploadService.cancelQueuedPostUpload(post)
257→        }
258→        triggerPostListAction.invoke(PostListAction.EditPost(site, post, loadAutoSaveRevision = false))
259→    }
260→
261→    fun deletePost(localPostId: Int) {
262→        // If post doesn't exist, nothing else to do
263→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
264→        criticalPostActionTracker.add(LocalId(post.id), DELETING_POST)
265→
266→        when {
267→            post.isLocalDraft -> {
268→                val pushId = PendingDraftsNotificationsUtils.makePendingDraftNotificationId(post.id)
269→                triggerPostListAction(DismissPendingNotification(pushId))
270→                dispatcher.dispatch(PostActionBuilder.newRemovePostAction(post))
271→            }
272→            else -> {
273→                dispatcher.dispatch(PostActionBuilder.newDeletePostAction(RemotePostPayload(post, site)))
274→            }
275→        }
276→    }
277→
278→    /**
279→     * This function handles a post being deleted and removed. Since deleting remote posts will trigger both delete
280→     * and remove actions we only want to remove the critical action when the post is actually successfully removed.
281→     *
282→     * It's possible to separate these into two methods that handles delete and remove. However, the fact that they
283→     * follow the same approach and the tricky nature of delete action makes combining the actions like so makes our
284→     * expectations clearer.
285→     */
286→    fun handlePostDeletedOrRemoved(localPostId: LocalId, isRemoved: Boolean, isError: Boolean) {
287→        if (criticalPostActionTracker.get(localPostId) != DELETING_POST) {
288→            /*
289→             * This is an unexpected action and either it has already been handled or another critical action has
290→             * been performed. In either case, safest action is to just ignore it.
291→             */
292→            return
293→        }
294→        if (isError) {
295→            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
296→        }
297→        if (isRemoved) {
298→            criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = DELETING_POST)
299→        }
300→    }
301→
302→    fun trashPostWithLocalChanges(localPostId: Int) {
303→        // If post doesn't exist, nothing else to do
304→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
305→        trashPost(post, true)
306→    }
307→
308→    fun trashPostWithUnsavedChanges(localPostId: Int) {
309→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
310→        trashPost(post)
311→    }
312→
313→    private fun trashPost(post: PostModel, hasLocalChanges: Boolean = false) {
314→        // We need network connection to trash a post
315→        if (!checkNetworkConnection()) {
316→            return
317→        }
318→        val criticalPostAction = if (hasLocalChanges) {
319→            TRASHING_POST_WITH_LOCAL_CHANGES
320→        } else {
321→            TRASHING_POST
322→        }
323→
324→        showSnackbar.invoke(SnackbarMessageHolder(UiStringRes(R.string.post_trashing)))
325→        criticalPostActionTracker.add(localPostId = LocalId(post.id), criticalPostAction = criticalPostAction)
326→
327→        triggerPostUploadAction.invoke(CancelPostAndMediaUpload(post))
328→        dispatcher.dispatch(PostActionBuilder.newDeletePostAction(RemotePostPayload(post, site)))
329→    }
330→
331→    @Suppress("UseCheckOrError")
332→    fun handlePostTrashed(localPostId: LocalId, isError: Boolean) {
333→        val criticalAction = criticalPostActionTracker.get(localPostId)
334→        if (criticalAction != TRASHING_POST && criticalAction != TRASHING_POST_WITH_LOCAL_CHANGES) {
335→            /*
336→             * This is an unexpected action and either it has already been handled or another critical action has
337→             * been performed. In either case, safest action is to just ignore it.
338→             */
339→            return
340→        }
341→        criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = criticalAction)
342→        if (isError) {
343→            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
344→        } else {
345→            val snackBarHolder = when (criticalAction) {
346→                TRASHING_POST -> SnackbarMessageHolder(
347→                    message = UiStringRes(R.string.post_trashed),
348→                    buttonTitle = UiStringRes(R.string.undo),
349→                    buttonAction = {
350→                        val post = postStore.getPostByLocalPostId(localPostId.value)
351→                        if (post != null) {
352→                            restorePost(post)
353→                        }
354→                    }
355→                )
356→                TRASHING_POST_WITH_LOCAL_CHANGES -> SnackbarMessageHolder(message = UiStringRes(R.string.post_trashed))
357→                else -> throw IllegalStateException("Unexpected action in handlePostTrashed(): $criticalAction")
358→            }
359→            showSnackbar.invoke(snackBarHolder)
360→        }
361→    }
362→
363→    private fun restorePost(post: PostModel) {
364→        // We need network connection to restore a post
365→        if (!checkNetworkConnection.invoke()) {
366→            return
367→        }
368→        showSnackbar.invoke(SnackbarMessageHolder(message = UiStringRes(R.string.post_restoring)))
369→        criticalPostActionTracker.add(localPostId = LocalId(post.id), criticalPostAction = RESTORING_POST)
370→        dispatcher.dispatch(PostActionBuilder.newRestorePostAction(RemotePostPayload(post, site)))
371→    }
372→
373→    fun handlePostRestored(localPostId: LocalId, isError: Boolean) {
374→        if (criticalPostActionTracker.get(localPostId) != RESTORING_POST) {
375→            /*
376→             * This is an unexpected action and either it has already been handled or another critical action has
377→             * been performed. In either case, safest action is to just ignore it.
378→             */
379→            return
380→        }
381→        criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = RESTORING_POST)
382→        if (isError) {
