 79→private val PostListDiffItemCallback = object : DiffUtil.ItemCallback<PostListItemType>() {
 80→    override fun areItemsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
 81→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
 82→            return true
 83→        }
 84→        if (oldItem is LoadingItem && newItem is LoadingItem) {
 85→            return oldItem.localOrRemoteId == newItem.localOrRemoteId
 86→        }
 87→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
 88→            return oldItem.data.localPostId == newItem.data.localPostId
 89→        }
 90→        if (oldItem is LoadingItem && newItem is PostListItemUiState) {
 91→            return when (oldItem.localOrRemoteId) {
 92→                is LocalId -> oldItem.localOrRemoteId == newItem.data.localPostId.id
 93→                is RemoteId -> oldItem.localOrRemoteId == newItem.data.remotePostId.id
 94→            }
 95→        }
 96→        return false
 97→    }
 98→
 99→    override fun areContentsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
100→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
101→            return true
102→        }
103→        if (oldItem is LoadingItem && newItem is LoadingItem) {
104→            return when (oldItem.localOrRemoteId) {
105→                is LocalId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? LocalId)?.value
106→                is RemoteId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? RemoteId)?.value
107→            }
108→        }
109→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
110→            return oldItem.data == newItem.data
111→        }
112→        return false
113→    }
114→
115→    override fun getChangePayload(oldItem: PostListItemType, newItem: PostListItemType): Any? {
116→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
117→            /**
118→             * Suppresses the default animation if the progress has changed to prevent blinking as the upload progresses
119→             *
120→             * We don't need to use the payload in onBindViewHolder unless we want to. Passing a non-null value
121→             * suppresses the default ItemAnimator, which is all we need in this case.
122→             */
123→            if (oldItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
124→                newItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
125→                oldItem.data.progressBarUiState.progress != newItem.data.progressBarUiState.progress
126→            ) {
127→                return true
128→            }
129→        }
130→        return super.getChangePayload(oldItem, newItem)
131→    }
132→}
